var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"ONIL_BORDER_NULL_NAMED","text":{"KOREA":"내가 들은 그 말들이 전부 사실이겠지, 피터?","JPN":"わしが聞いた言葉は全て事実じゃろう、ピーター。","ENG":"Everything I just heard has gotta be true, right Peter?","TWN":"我聽到的那些話都是事實的吧，彼得？"},"stage":{"bg":"NOMAD_VILLAGE","slots":{"L":null,"C":null,"R":{"char_id":"ONIL_BORDER_NULL_NAMED","face":"UNIT_IDLE"}}}},{"id":"L3_1","type":"dialog","speaker":"PITER_BORDER_NULL_NAMED","text":{"KOREA":"그렇긴 한데… 아무래도 기억 자체가 온전하지 못한 것 같았어요.","JPN":"そうですけど……どうやら記憶自体が完全じゃないようでしたよ。","ENG":"Yes, but... I think his memories aren't fully intact.","TWN":"話雖如此……但我看他好像失去記憶一樣。"},"stage":{"bg":"NOMAD_VILLAGE","slots":{"L":{"char_id":"PITER_BORDER_NULL_NAMED","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ONIL_BORDER_NULL_NAMED","face":"UNIT_IDLE"}}}},{"id":"L4_1","type":"dialog","speaker":"PITER_BORDER_NULL_NAMED","text":{"KOREA":"마치 과거에 살다가 온 사람처럼…","JPN":"まるで過去から来た人みたいに……","ENG":"It's as if he's been living in the past...","TWN":"感覺就像從過去來到現代的人…"},"stage":{"bg":"NOMAD_VILLAGE","slots":{"L":{"char_id":"PITER_BORDER_NULL_NAMED","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ONIL_BORDER_NULL_NAMED","face":"UNIT_IDLE"}}}},{"id":"L6_1","type":"dialog","speaker":null,"text":{"KOREA":"큐리안이면 그 실종됐다던 총사대장 아냐?","JPN":"キュリアンって、あの行方不明になったっていう銃士隊長じゃないか？","ENG":"\\"Curian\\"? Isn't that the General Musketeer who went missing?","TWN":"庫里安不就是那個失蹤的隊長嗎？"},"stage":{"bg":"NOMAD_VILLAGE","slots":{"L":{"char_id":"PITER_BORDER_NULL_NAMED","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ONIL_BORDER_NULL_NAMED","face":"UNIT_IDLE"}}}},{"id":"L7_1","type":"dialog","speaker":null,"text":{"KOREA":"뭔가 수상하긴 했어. 왕실 군복 차림에 병기마까지 타고 있었다며.","JPN":"どこか怪しいと思ったのよ。王室の軍服姿で、兵器馬にまで乗ってたらしいじゃない。","ENG":"I knew something was up. Wasn't he wearing the Royal Army uniform and riding on an Armored Horse?","TWN":"確實有點可疑，聽說他身穿皇家軍裝，還騎在戰馬上。"},"stage":{"bg":"NOMAD_VILLAGE","slots":{"L":{"char_id":"PITER_BORDER_NULL_NAMED","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ONIL_BORDER_NULL_NAMED","face":"UNIT_IDLE"}}}},{"id":"L8_1","type":"dialog","speaker":null,"text":{"KOREA":"20년 전 사람이 왜 이제서야 여기 나타나? 뭔가 착각한 거겠지.","JPN":"20年の前の人間がなんで今更ここに現れるんだ？　何かの間違いだろう。","ENG":"But why would a person from 20 years ago suddenly appear here? I'm sure there must be an explanation for all of this.","TWN":"二十年前的人怎麼現在才出現在這裡？應該哪裡有誤會吧？"},"stage":{"bg":"NOMAD_VILLAGE","slots":{"L":{"char_id":"PITER_BORDER_NULL_NAMED","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ONIL_BORDER_NULL_NAMED","face":"UNIT_IDLE"}}}},{"id":"L9_1","type":"dialog","speaker":null,"text":{"KOREA":"사실이라면 당장 내쫓아야 하는 거 아녜요? 재건단 사람들에게 오해 받긴 싫다고요.","JPN":"本当なら今すぐ追い出さなきゃダメなんじゃないですか？　再建団の人たちに誤解されたくないわ。","ENG":"If what he says is true, shouldn't we immediately kick him out? I don't want the Alliance people to get the wrong idea.","TWN":"如果是真的，那應該馬上把他趕出去吧？我不才想被重建委員會的人誤會。"},"stage":{"bg":"NOMAD_VILLAGE","slots":{"L":{"char_id":"PITER_BORDER_NULL_NAMED","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ONIL_BORDER_NULL_NAMED","face":"UNIT_IDLE"}}}},{"id":"L10_1","type":"dialog","speaker":null,"text":{"KOREA":"내쫓긴 뭘 내쫓아? 당장 끌고가서 심판을 받게 해야지!","JPN":"追い出すも何も、今すぐ捕まえて審判するべきだよ！","ENG":"What do you mean \\"kick him out\\"? We should drag him out and bring him judgment!","TWN":"怎麼可以把他趕走？要馬上把他抓去受審吧！"},"stage":{"bg":"NOMAD_VILLAGE","slots":{"L":{"char_id":"PITER_BORDER_NULL_NAMED","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ONIL_BORDER_NULL_NAMED","face":"UNIT_IDLE"}}}},{"id":"L12_1","type":"dialog","speaker":"ONIL_BORDER_NULL_NAMED","text":{"KOREA":"피터, 수비대를 불러라.","JPN":"ピーター、守備隊を呼びなさい。","ENG":"Peter, call the guards.","TWN":"彼得，叫護衛隊。"},"stage":{"bg":"NOMAD_VILLAGE","slots":{"L":null,"C":{"char_id":"ONIL_BORDER_NULL_NAMED","face":"UNIT_IDLE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"PITER_BORDER_NULL_NAMED","text":{"KOREA":"그럼… 저 사람은 어떻게 되는 거죠?","JPN":"じゃあ……あの人はどうなるんですか？","ENG":"Then... What's gonna happen to him?","TWN":"那…他會變成怎樣？"},"stage":{"bg":"NOMAD_VILLAGE","slots":{"L":null,"C":{"char_id":"ONIL_BORDER_NULL_NAMED","face":"UNIT_IDLE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"ONIL_BORDER_NULL_NAMED","text":{"KOREA":"제라드 큐리안은 국가지명수배자다. 군법에 따라 재판을 받게 해야지.","JPN":"ジェラード・キュリアンは国家指名手配犯だ。軍法に従って裁判しなければ。","ENG":"Gerard Curian is a wanted criminal. He'll be tried according to military law.","TWN":"傑瑞德· 庫里安是國家通緝犯，應該按照軍法受審。"},"stage":{"bg":"NOMAD_VILLAGE","slots":{"L":null,"C":{"char_id":"ONIL_BORDER_NULL_NAMED","face":"UNIT_IDLE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"NOMAD_BORDER_NULL_ANGER","text":{"KOREA":"촌장님! 놈은 열쇠를 가지고 도망친 배신자라고요!","JPN":"村長！　やつは鍵を持って逃げた裏切り者ですよ！","ENG":"But Chief! He's the traitor who ran away with the Key!","TWN":"村長！這傢伙是拿走鑰匙逃跑的叛徒！"},"stage":{"bg":"NOMAD_VILLAGE","slots":{"L":null,"C":{"char_id":"ONIL_BORDER_NULL_NAMED","face":"UNIT_IDLE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"NOMAD_BORDER_NULL_ANGER","text":{"KOREA":"우리가 써야 할 약으로 치료해 준 것도 열불나는데 감옥에서 여생을 보내게 해 준다니요?","JPN":"治療に私たちの薬を使ったのも腹立たしいのに、牢獄で余生を送ることを許すなんて！","ENG":"We've already wasted precious medicine in treating this traitor! But now you want us to let him rot in jail for the rest of his life?!","TWN":"竟然把我們要用的藥拿去給他治療，怎麼可以讓他在監獄裡度過餘生這麼好過？"},"stage":{"bg":"NOMAD_VILLAGE","slots":{"L":null,"C":{"char_id":"ONIL_BORDER_NULL_NAMED","face":"UNIT_IDLE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":null,"text":{"KOREA":"옳소! 이런 법이 어디 있습니까!","JPN":"そうだ！　どういうことですか！","ENG":"Yeah! What kind of justice is that?!","TWN":"沒錯！哪有這種事！"},"stage":{"bg":"NOMAD_VILLAGE","slots":{"L":null,"C":{"char_id":"ONIL_BORDER_NULL_NAMED","face":"UNIT_IDLE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":null,"text":{"KOREA":"읏!","JPN":"うっ！","ENG":"Ngh!","TWN":"呃！"},"stage":{"bg":"AB_UI_NKM_UI_CUTSCEN_FX_BLOOD_SPREAD","slots":{"L":null,"C":null,"R":null}}},{"id":"L24_1","type":"dialog","speaker":"ELLA_BORDER_NULL_NULL","text":{"KOREA":"상처가 아직도 안 아물었나?","JPN":"傷がまだ治ってないのね。","ENG":"It still hasn't healed?","TWN":"傷口還沒好嗎？"},"stage":{"bg":"WORKSHOP","slots":{"L":null,"C":{"char_id":"ELLA_BORDER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"ELLA_BORDER_NULL_NULL","text":{"KOREA":"카운터라는 것도 이럴 때는 정말이지 쓸모가 없군.","JPN":"カウンターってのもこんな時にはまったく役に立たないね。","ENG":"I guess being a Counter is pretty useless at times like this.","TWN":"在這種時候，就算是制裁者也沒什麼用嘛。"},"stage":{"bg":"WORKSHOP","slots":{"L":null,"C":{"char_id":"ELLA_BORDER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}}]`);export{e as default};